head.script:
/**
 * @component
 * @componentName udc_side
 * @pluginName
 * @company
 * @developer
 * @category /cm/xml
 * @notSupportBrowser
 * @version
 * @htmlRender
 * @icon
 * @disableIcon
 * @description
 * @width
 * @height
 * @license
 * @imagePath
 * @homepage
 */
scwin.onpageload = function() {
    scwin.myMenuSearch();
    sbx_selectbox1.setNodeSet("data:"+$p.top().wfm_header.getWindow().ds_menuTop.id, "menuNm", "sysCd")
}

scwin.getCoClsCd = function() {
    let coClsCd = "";

    try {
        coClsCd = $c.data.getMemInfo("coClsCd") || "";
    } catch (e) {}

    try {
        if (!coClsCd && $p.top().dma_memInfo) {
            coClsCd = $p.top().dma_memInfo.get("coClsCd") || "";
        }
    } catch (e) {}

    return coClsCd;
};

scwin.filterSubCompanyNcallMenu = function(menuList) {
    if (scwin.getCoClsCd() == "0" || scwin.getCoClsCd() == "") {
        return menuList || [];
    }

    return (menuList || []).filter(function(menu) {
        const menuId = ((menu && menu.menuId) || "").toLowerCase();
        const menuNm = (menu && menu.menuNm) || "";

        return menuId.indexOf("n") === -1
            && menuNm.indexOf("엔콜") === -1;
    });
};

scwin.menuOpenStateTimer = null;
scwin.serverMode = window.location.hostname.indexOf("newdevdebis.dongwon.com") > -1 ? "dev" :
                   window.location.hostname.indexOf("newdebis.dongwon.com") > -1 ? "prd" : "local";
scwin.useMenuOpenState = true;
scwin.useMenuOpenStateBlock = scwin.serverMode === "prd";

scwin.isMenuClosed = function(node) {
    const openYn = (node && node.openYn != null) ? String(node.openYn).trim().toUpperCase() : "";
    return openYn === "0";
};

scwin.hasMenuProgram = function(node) {
    const programId = node ? (node.actPgmId || node.pgmId || "") : "";
    return String(programId).trim() !== "";
};

scwin.applyTreeMenuOpenState = function(treeView, menuList) {
    if (!treeView || !treeView.removeNodeClass || !treeView.setNodeClass) {
        return;
    }

    for (const row of menuList) {
        const nodeId = row ? row.menuId : "";
        if (!nodeId) {
            continue;
        }

        treeView.removeNodeClass(nodeId, false, "tvw_red");
        treeView.removeNodeClass(nodeId, false, "tvw_gray");
        treeView.removeNodeClass(nodeId, false, "txt-red");
        treeView.removeNodeClass(nodeId, false, "txt-gray");

        if (scwin.useMenuOpenState && scwin.hasMenuProgram(row) && scwin.isMenuClosed(row)) {
            treeView.setNodeClass(nodeId, "txt-gray");
        }
    }
};

scwin.applyMenuOpenState = function() {
    scwin.applyTreeMenuOpenState(trv_treeview, ds_trvMenu.getAllJSON() || []);
    scwin.applyTreeMenuOpenState(trv_myTree, ds_fav.getAllJSON() || []);
};

scwin.scheduleApplyMenuOpenState = function() {
    if (scwin.menuOpenStateTimer) {
        clearTimeout(scwin.menuOpenStateTimer);
    }

    scwin.menuOpenStateTimer = setTimeout(function() {
        scwin.applyMenuOpenState();
    }, 0);
};

scwin.searchMenuSnapshot = [];
scwin.searchInProgress = false;
scwin.searchAlertOpen = false;
scwin.searchEnterLocked = false;
scwin.searchEnterLockTimer = null;

scwin.lockSearchEnter = function(delay) {
    if (scwin.searchEnterLockTimer) {
        clearTimeout(scwin.searchEnterLockTimer);
    }

    scwin.searchEnterLocked = true;
    scwin.searchEnterLockTimer = setTimeout(function() {
        scwin.searchEnterLocked = false;
        scwin.searchEnterLockTimer = null;
    }, delay || 300);
};

scwin.showSearchAlert = function(message, focusInput) {
    scwin.searchAlertOpen = true;
    scwin.lockSearchEnter(300);

    try {
        ibx_input3.blur();
    } catch (e) {}

    $c.win.alert(message, function() {
        scwin.lockSearchEnter(300);

        setTimeout(function() {
            scwin.searchAlertOpen = false;

            if (focusInput) {
                try {
                    ibx_input3.focus();
                } catch (e) {}
            }
        }, 0);
    });
};

scwin.ensureOriginTrvMenu = function(menuList) {
    const originMenuList = ds_originTrvMenu.getAllJSON() || [];
    const currentMenuList = menuList || ds_trvMenu.getAllJSON() || [];

    if (originMenuList.length === 0 && currentMenuList.length > 0) {
        ds_originTrvMenu.setJSON(currentMenuList);
    }
};

scwin.getRestoreTrvMenu = function() {
    const originMenuList = ds_originTrvMenu.getAllJSON() || [];

    if (originMenuList.length > 0) {
        return originMenuList;
    }

    return scwin.searchMenuSnapshot || [];
};

scwin.getCurrentSysCd = function() {
    let sysCd = "";

    try {
        if ($p.top().wfm_header && $p.top().wfm_header.getWindow) {
            const headerWin = $p.top().wfm_header.getWindow();

            if (headerWin && headerWin.dma_userParam) {
                sysCd = headerWin.dma_userParam.get("sysCd") || "";
            }

            if (!sysCd && headerWin && headerWin.scwin) {
                sysCd = headerWin.scwin.sysCd || "";
            }
        }
    } catch (e) {}

    try {
        if (!sysCd) {
            sysCd = WebSquare.localStorage.getItem("sysCd") || "";
        }
    } catch (e) {}

    return sysCd;
};

scwin.useLocalMenuSearch = function() {
    try {
        if ($p.top().wfm_header && $p.top().wfm_header.getWindow) {
            const headerWin = $p.top().wfm_header.getWindow();

            if (headerWin && headerWin.ds_menuTop) {
                return headerWin.ds_menuTop.getRowCount() === 0;
            }
        }
    } catch (e) {}

    return false;
};

scwin.normalizeMenuSearchText = function(value) {
    return String(value || "").replace(/\s+/g, "").toLowerCase();
};

scwin.getLocalMenuSource = function() {
    const originMenuList = ds_originTrvMenu.getAllJSON() || [];

    if (originMenuList.length > 0) {
        return originMenuList;
    }

    if ((scwin.searchMenuSnapshot || []).length > 0) {
        return scwin.searchMenuSnapshot;
    }

    return ds_trvMenu.getAllJSON() || [];
};

scwin.searchMenuLocal = function(keyword) {
    const sourceMenuList = scwin.getLocalMenuSource();
    const normalizedKeyword = scwin.normalizeMenuSearchText(keyword);

    if (!normalizedKeyword || sourceMenuList.length === 0) {
        return [];
    }

    const menuMap = {};
    const includedMenuMap = {};

    for (const row of sourceMenuList) {
        menuMap[row.menuId] = row;
    }

    const includeAncestors = function(menuId) {
        let currentMenuId = menuId;

        while (currentMenuId && menuMap[currentMenuId]) {
            if (includedMenuMap[currentMenuId]) {
                break;
            }

            includedMenuMap[currentMenuId] = true;
            currentMenuId = menuMap[currentMenuId].upperMenuId || "";
        }
    };

    const includeDescendants = function(startIndex) {
        const baseDepth = Number(sourceMenuList[startIndex].lvl) || 0;

        for (let index = startIndex + 1; index < sourceMenuList.length; index++) {
            const currentDepth = Number(sourceMenuList[index].lvl) || 0;

            if (currentDepth <= baseDepth) {
                break;
            }

            includedMenuMap[sourceMenuList[index].menuId] = true;
        }
    };

    for (let index = 0; index < sourceMenuList.length; index++) {
        const row = sourceMenuList[index];
        const searchTarget = scwin.normalizeMenuSearchText([row.menuNm, row.actPgmNm, row.actPgmId].join(" "));

        if (searchTarget.indexOf(normalizedKeyword) > -1) {
            includedMenuMap[row.menuId] = true;
            includeAncestors(row.menuId);
            includeDescendants(index);
        }
    }

    return sourceMenuList.filter(function(row) {
        return !!includedMenuMap[row.menuId];
    });
};

scwin.applySearchResult = function(menuList) {
    ds_trvMenu.setJSON(menuList || []);
    trv_treeview.spanAll(true);
    scwin.scheduleApplyMenuOpenState();
};

scwin.restoreSearchResult = function() {
    ds_trvMenu.setJSON(scwin.getRestoreTrvMenu());
    scwin.scheduleApplyMenuOpenState();
};

scwin.dlt_menu_ondataload = function() {
    if (!scwin.searchInProgress) {
        scwin.ensureOriginTrvMenu();
    }

    scwin.scheduleApplyMenuOpenState();
};

scwin.sbm_submission1_submitdone = function () {
    ds_fav.setJSON(scwin.filterSubCompanyNcallMenu(ds_fav.getAllJSON()));
    var menuArray = ds_fav.getAllJSON();
    for (const row of menuArray) {
        switch (row.pgmId) {
            case "op_304_01_01b.jsp":
                row.pgmScrPath = "/ds/op/wrkrslts/transwrkrslts/";
            break;
            case "op_304_01_02b.jsp":
                row.pgmScrPath = "/ds/op/wrkrslts/transwrkrslts/";
            break;
            case "as_102_01_02b.jsp":
                row.pgmScrPath = "/ds/as/cstmrsrvc/coafmgnt/";
            break;
            case "as_102_01_03b.jsp":
                row.pgmScrPath = "/ds/as/cstmrsrvc/coafmgnt/";
            break;
            case "op_301_01_05b.jsp":
                if(row.menuId.indexOf("n") !== -1){
                    row.pgmId = "op_301_01_19b.jsp" //반입등록
                }
            break;
            case "op_301_01_06b.jsp":
                if(row.menuId.indexOf("n") !== -1){
                    row.pgmId = "op_301_01_09b.jsp" //반출등록
                }
            break;
            case "op_304_01_06b.jsp":
                row.pgmScrPath = "/ds/op/wrkrslts/transwrkrslts/";
            break;
            case "fs_103_03_01b.jsp":
                if(row.menuId.indexOf("n") !== -1){
                    row.pgmId = "fs_103_03_02b.jsp" //협력업체 세금계산서 발행
                }
            break;
            case "op_204_04_01b.jsp":
                if(row.menuId.indexOf("n") !== -1){
                    row.pgmScrPath = "/tn/op/transwrkindict/cntr/";
                    row.pgmId = "tn_304_03_09b.jsp" //CY구역관리
                }
            break;
            case "op_301_01_17b.jsp":
                if(row.menuId.indexOf("n") !== -1){
                    row.pgmId = "op_301_01_20b.jsp" //반출입 정보 수정
                }
            break;
            case "op_304_01_65b.jsp":
                if(row.menuId.indexOf("n") !== -1){
                    row.pgmScrPath = "/tn/op/transwrkindict/cntr/";
                    row.pgmId = "tn_304_01_12b.jsp" //출도착등록(컨테이너)(협럭업체용)
                }
            break;
            case "op_202_02_07b.jsp":
                if(row.menuId.indexOf("n") !== -1){
                    row.pgmId = "op_202_02_08b.jsp" //셔틀운송작업물량차량조회
                }
            break;
            case "sd_402_01_35t.jsp":
                if(row.menuId.indexOf("n") !== -1){
                    row.pgmId = "sd_402_01_35b.jsp"; //오더요청등록(크나우프)
                }
            break;
        }
    }
    ds_fav.setJSON(menuArray);
    scwin.scheduleApplyMenuOpenState();
    trv_myTree.spanAll(false);
};

scwin.applySearchMenuContext = function(node) {
    let resolvedSysCd = (node && node.sysCd) ? node.sysCd : "";
    const menuId = (node && node.menuId) ? node.menuId : "";

    if (menuId && menuId.toLowerCase().indexOf("n") !== -1) {
        resolvedSysCd = "NC";
    }

    try {
        if (resolvedSysCd && $p.top().wfm_header && $p.top().wfm_header.getWindow) {
            const headerWin = $p.top().wfm_header.getWindow();
            if (headerWin && headerWin.dma_userParam) {
                if (headerWin.scwin) {
                    headerWin.scwin.sysCd = resolvedSysCd;
                }
                headerWin.dma_userParam.set("sysCd", resolvedSysCd);
                headerWin.dma_userParam.set("systemClsCd", resolvedSysCd === "NC" ? "NTIS" : "");
            }
        }
    } catch (e) {}

    try {
        if (resolvedSysCd) {
            WebSquare.localStorage.setItem("sysCd", resolvedSysCd);
        }
    } catch (e) {}

    try {
        if ($p.top().dma_mem) {
            $p.top().dma_mem.set("authMenuId", menuId || "");
            $p.top().dma_mem.set("authSysCd", resolvedSysCd || "");
        }
    } catch (e) {}

    return resolvedSysCd;
};


// 왼쪽 트리 워킹메뉴 클릭
scwin.trv_treeview_onlabelclick = function (value, node, index) {//debugger;
    if (scwin.useMenuOpenStateBlock && scwin.hasMenuProgram(node) && scwin.isMenuClosed(node)) {
        $c.win.alert("해당 화면은 현재 점검 및 준비 중 입니다.");
        return;
    }

    if(node.actPgmScrPath && node.actPgmId) {
        trv_treeview.spanAll(false);
        const resolvedSysCd = scwin.applySearchMenuContext(node);
        let prefix = "/ui"
        prefix += node.actPgmScrPath.substring(0,1) !== "/" ? "/" : "";

        if(node.actPgmScrPath.indexOf("/sample") > -1 || node.actPgmScrPath.indexOf("/pub") > -1 || node.actPgmScrPath.indexOf("/ui") > -1) {
            prefix = ""
        }
        let src = prefix+node.actPgmScrPath+node.actPgmId;
        src = src.replace(/.jsp/g,".xml");

        $c.win.openMenu(node.menuNm,src,node.actPgmId,null,{pgmNm : node.actPgmNm,menuId : node.menuId, sysCd : resolvedSysCd || node.sysCd, menuParam : node.menuParam, openAction: "select" });
        trv_treeview.findNodeByIndex(index,true);
    }
};


/**
 * @method
 * @name hasFavCode
 * @description 
 * 즐겨찾기 리스트에서 menuCode가 추가되어있는지 확인후 개수 반환.
 * 없으면 == 0, 있으면 > 0 
 * @hidden N
 * @exception 
 */
scwin.hasFavCode = function (menuCode) {
    return (ds_fav.getMatchedIndex("pgmId", menuCode, true)).length;
}

/**
 * @method
 * @name getMenuNavigation
 * @description 메뉴 Navigation 정보를 가져온다
 * @param {string} menuCode 메뉴 코드
 * @param {string} rsStr 문자열
 * @hidden N
 * @exception 
 */
scwin.getMenuNavigation = function (menuCode, rsStr) {
    let naviStr;
    if (rsStr) {
        naviStr = rsStr;
    } else {
        naviStr = "";
    }
    const menuJSON = ds_menu.getMatchedJSON("MENU_CD", menuCode, true)[0];

    naviStr += menuJSON.MENU_NM + "%|%" + menuCode + "%|%";

    if (menuJSON) {
        if (menuJSON.PARENT_MENU_CD != "000000000") {
            return this.getMenuNavigation(menuJSON.PARENT_MENU_CD, naviStr);
        }
    }
    return naviStr;
};

/**
 * @method
 * @name myMenuSearch
 * @description 마이메뉴 조회
 * @param
 * @returns
 * @hidden N
 * @exception
 * @example
 */
scwin.myMenuSearch = function () {
    dma_userParam.set("userId", WebSquare.localStorage.getItem("userId") || $c.data.getMemInfo("userId"));
    $c.sbm.execute(sbm_getMyMenuList);
};

// 마이메뉴
scwin.trv_myTreeview_onlabelclick = function (value, node, index) {//debugger;
    if (scwin.useMenuOpenStateBlock && scwin.hasMenuProgram(node) && scwin.isMenuClosed(node)) {
        $c.win.alert("해당 화면은 현재 점검 및 준비 중 입니다.");
        return;
    }

    if(node.pgmScrPath && node.pgmId) {
        trv_myTree.spanAll(false);
        const resolvedSysCd = scwin.applySearchMenuContext(node);
        let prefix = "/ui"
        prefix += node.pgmScrPath.substring(0,1) !== "/" ? "/" : "";
        if(node.pgmScrPath.indexOf("/sample") > -1 || node.pgmScrPath.indexOf("/pub") > -1 || node.pgmScrPath.indexOf("/ui") > -1) {
            prefix = ""
        }
        let src = prefix+node.pgmScrPath+node.pgmId;
        src = src.replace(/.jsp/g,".xml");
//debugger;
         $c.win.openMenu(node.menuNm,src,node.pgmId,null,{pgmNm : node.pgmNm,menuId : node.menuId, sysCd : resolvedSysCd || node.sysCd, menuParam : node.menuParam });
        trv_myTree.findNodeByIndex(index,true);
    }
};

scwin.ibx_input3_oneditkeyup = function (info, e) {
    if(info.keyCode == 13) {
        if (scwin.searchAlertOpen || scwin.searchEnterLocked || scwin.searchInProgress) {
            return;
        }

        scwin.lockSearchEnter();
        let val = info.newValue;
        scwin.searchMenu(val);
    }
};
// 메뉴검색
scwin.searchMenu = function(val) {//debugger;
    if (scwin.searchAlertOpen || scwin.searchInProgress) {
        return;
    }

    if(!val) {
        scwin.showSearchAlert("검색어를 입력해주세요", true);
        return;
    } else {
        let memObj = $c.data.getMemInfo();
        const searchKeyword = val.trimAll();
        let sysCd = sbx_selectbox1.getValue();

        if (!sysCd) {
            sysCd = scwin.getCurrentSysCd();
        }

        if(sysCd && sysCd !== "all") {
            dma_search.set("sysCd", sysCd);
            dma_search.set("coCd", memObj.coCd);
        } else {
            dma_search.set("sysCd", "");
            if( memObj.coCd === "000"){
                dma_search.set("coCd", "tobe");
            }
            else if(memObj.coCd === ""){
                dma_search.set("coCd", "blankDsSearch");
            }
            else if(memObj.coCd === "017"){
                dma_search.set("coCd", "tobe017");
            }
            else{
                dma_search.set("coCd", "tobeCompany");
            }


        }


        // if(memObj.userClsCd == "01") {
        // } else {
        // }
        scwin.searchMenuSnapshot = ds_trvMenu.getAllJSON() || [];
        scwin.searchInProgress = true;

        if (scwin.useLocalMenuSearch()) {
            const localMenuList = scwin.searchMenuLocal(searchKeyword);

            scwin.searchInProgress = false;

            if (localMenuList.length === 0) {
                scwin.showSearchAlert("조회된 데이터가 없습니다.");
                scwin.restoreSearchResult();
                return;
            }

            scwin.applySearchResult(localMenuList);
            return;
        }

        dma_search.set("userId", memObj.userId);
        dma_search.set("menuNm", searchKeyword);
        $c.sbm.execute(sbm_allMenuList);
    }

}


scwin.sbm_allMenuList_submitdone = function (e) {
    var menuArray = (e.responseJSON && e.responseJSON.GAUCE) || [];
    for (const row of menuArray) {
        switch (row.actPgmId) {
            case "op_304_01_01b.jsp":
            row.actPgmScrPath = "/ds/op/wrkrslts/transwrkrslts/";
            break;
            case "op_304_01_02b.jsp":
            row.actPgmScrPath = "/ds/op/wrkrslts/transwrkrslts/";
            break;
            case "as_102_01_02b.jsp":
            row.actPgmScrPath = "/ds/as/cstmrsrvc/coafmgnt/";
            break;
            case "as_102_01_03b.jsp":
            row.actPgmScrPath = "/ds/as/cstmrsrvc/coafmgnt/";
            break;
            case "op_301_01_05b.jsp":
                if(row.menuId.indexOf("n") !== -1){
                    row.actPgmId = "op_301_01_19b.jsp" //반입등록
                }
                break;
            case "op_301_01_06b.jsp":
                if(row.menuId.indexOf("n") !== -1){
                    row.actPgmId = "op_301_01_09b.jsp" //반출등록
                }
                break;
            case "op_304_01_06b.jsp":
                row.actPgmScrPath = "/ds/op/wrkrslts/transwrkrslts/";
                break;
            case "fs_103_03_01b.jsp":
                if(row.menuId.indexOf("n") !== -1){
                    row.actPgmId = "fs_103_03_02b.jsp" //협력업체 세금계산서 발행
                }
                break;
            case "op_204_04_01b.jsp":
                if(row.menuId.indexOf("n") !== -1){
                    row.actPgmScrPath = "/tn/op/transwrkindict/cntr/";
                    row.actPgmId = "tn_304_03_09b.jsp" //CY구역관리
                }
                break;
            case "op_301_01_17b.jsp":
                if(row.menuId.indexOf("n") !== -1){
                    row.actPgmId = "op_301_01_20b.jsp" //반출입 정보 수정
                }
                break;
            case "op_304_01_65b.jsp":
                if(row.menuId.indexOf("n") !== -1){
                    row.actPgmScrPath = "/tn/op/transwrkindict/cntr/";
                    row.actPgmId = "tn_304_01_12b.jsp" //출도착등록(컨테이너)(협럭업체용)
                }
                break;
            case "op_202_02_07b.jsp":
                if(row.menuId.indexOf("n") !== -1){
                    row.actPgmId = "op_202_02_08b.jsp" //셔틀운송작업물량차량조회
                }
                break;
            case "sd_402_01_35t.jsp":
                if(row.menuId.indexOf("n") !== -1){
                    row.actPgmId = "sd_402_01_35b.jsp"; //오더요청등록(크나우프)
                }
                break;


        }
    }
    menuArray = scwin.filterSubCompanyNcallMenu(menuArray);
    scwin.searchInProgress = false;
    if(menuArray.length == 0){
        const localMenuList = scwin.searchMenuLocal(dma_search.get("menuNm"));

        if (localMenuList.length > 0) {
            scwin.applySearchResult(localMenuList);
            return;
        }

        scwin.showSearchAlert("조회된 데이터가 없습니다.");
        scwin.restoreSearchResult();
        return;
    }
    scwin.applySearchResult(menuArray);
};

// 검색버튼 클릭시 
scwin.btn_trigger1_onclick = function (e) {
    if (scwin.searchAlertOpen || scwin.searchInProgress) {
        return;
    }

    let val = ibx_input3.getValue();
    scwin.searchMenu(val);

};
